/*Table structure for table `account` */

DROP TABLE IF EXISTS `account`;

CREATE TABLE `account` (
  `PARTY_ID` varchar(20) NOT NULL,
  `FIRST_NAME` varchar(100) default NULL,
  `MIDDLE_NAME` varchar(100) default NULL,
  `LAST_NAME` varchar(100) default NULL,
  `GENDER` varchar(20) default NULL,
  `PHONE_NUMBER` varchar(50) default NULL,
  `ADDRESS1` varchar(200) default NULL,
  `ADDRESS2` varchar(200) default NULL,
  `CITY` varchar(50) default NULL,
  `STATE` varchar(20) default NULL,
  `COUNTRY` varchar(20) default NULL,
  `ZIP` varchar(50) default NULL,
  `ACCOUNT_ID` varchar(20) default NULL,
  `EMAIL_ADDRESS` varchar(50) default NULL,
  `PASSWORD` varchar(20) default NULL,
  `CARD_TYPE` varchar(50) default NULL,
  `CARD_NUMBER` varchar(50) default NULL,
  `CARD_EXP_MONTH` varchar(20) default NULL,
  `CARD_EXP_YEAR` varchar(20) default NULL,
  `CARD_ID` varchar(50) default NULL,
  `CARD_HOLDER_NAME` varchar(200) default NULL,
  `BILLING_ADDRESS` varchar(200) default NULL,
  `BILLING_CITY` varchar(50) default NULL,
  `BILLING_STATE` varchar(20) default NULL,
  `BILLING_ZIP` varchar(50) default NULL,
  `ACCOUNT_NUMBER` int(1) default NULL,
  `NOTATION` varchar(20) default NULL,
  `EXTENDED` int(11) default NULL,
  PRIMARY KEY  (`PARTY_ID`),
  KEY `ACCOUNT_ID` (`ACCOUNT_ID`)
) ENGINE=InnoDB DEFAULT CHARSET=latin1;

/*Data for the table `account` */

insert  into `account`(`PARTY_ID`,`FIRST_NAME`,`MIDDLE_NAME`,`LAST_NAME`,`GENDER`,`PHONE_NUMBER`,`ADDRESS1`,`ADDRESS2`,`CITY`,`STATE`,`COUNTRY`,`ZIP`,`ACCOUNT_ID`,`EMAIL_ADDRESS`,`PASSWORD`,`CARD_TYPE`,`CARD_NUMBER`,`CARD_EXP_MONTH`,`CARD_EXP_YEAR`,`CARD_ID`,`CARD_HOLDER_NAME`,`BILLING_ADDRESS`,`BILLING_CITY`,`BILLING_STATE`,`BILLING_ZIP`,`ACCOUNT_NUMBER`,`NOTATION`,`EXTENDED`) values ('demo','John','','Doe','M','','','','New Jersey','','US','','demo','','demo','','','','','','','','','','',1,'Universal',1),('system','System','','','M','','','','','','US','','system',NULL,'system','','','','','','','','','','',1,'Universal',0);

/*Table structure for table `appointment` */

DROP TABLE IF EXISTS `appointment`;

CREATE TABLE `appointment` (
  `ID` int(11) NOT NULL auto_increment,
  `TRANS_DATE` date default NULL,
  `TRANS_TIME` time default NULL,
  `DURATION` int(11) default NULL,
  `PATIENT_ID` varchar(20) default NULL,
  `REMARKS` varchar(200) default NULL,
  `ACCOUNT_ID` varchar(20) default NULL,
  PRIMARY KEY  (`ID`),
  KEY `ACCOUNT_ID` (`ACCOUNT_ID`),
  KEY `TRANS_DATE` (`TRANS_DATE`),
  KEY `TRANS_TIME` (`TRANS_TIME`),
  KEY `PATIENT_ID` (`PATIENT_ID`)
) ENGINE=InnoDB DEFAULT CHARSET=latin1;

/*Data for the table `appointment` */

/*Table structure for table `attendance` */

DROP TABLE IF EXISTS `attendance`;

CREATE TABLE `attendance` (
  `ID` int(11) NOT NULL auto_increment,
  `TRANS_DATE` date default NULL,
  `DOCTOR_ID` varchar(20) default NULL,
  `DOCTOR` varchar(200) default NULL,
  `NUM_DAYS` double default NULL,
  `ACCOUNT_ID` varchar(20) default NULL,
  PRIMARY KEY  (`ID`),
  KEY `DOCTOR_ID` (`DOCTOR_ID`),
  KEY `TRANS_DATE` (`TRANS_DATE`),
  KEY `ACCOUNT_ID` (`ACCOUNT_ID`)
) ENGINE=InnoDB DEFAULT CHARSET=latin1;

/*Data for the table `attendance` */

/*Table structure for table `country_code` */

DROP TABLE IF EXISTS `country_code`;

