/*Table structure for table `coverage` */

DROP TABLE IF EXISTS `coverage`;

CREATE TABLE `coverage` (
  `COVERAGETYPE` varchar(20) NOT NULL,
  PRIMARY KEY  (`COVERAGETYPE`)
) ENGINE=InnoDB DEFAULT CHARSET=latin1;

/*Data for the table `coverage` */

insert  into `coverage`(`COVERAGETYPE`) values ('BASIC');

/*Table structure for table `coverage_entry` */

DROP TABLE IF EXISTS `coverage_entry`;

CREATE TABLE `coverage_entry` (
  `ID` int(11) NOT NULL auto_increment,
  `COVERAGETYPE` varchar(20) default NULL,
  `CODEFROM` varchar(20) default NULL,
  `CODETO` varchar(20) default NULL,
  `DESCRIPTION` varchar(200) default NULL,
  `COVERAGE` double default NULL,
  PRIMARY KEY  (`ID`)
) ENGINE=InnoDB DEFAULT CHARSET=latin1;

/*Data for the table `coverage_entry` */

