  `PHONE_NUMBER` varchar(50) default NULL,
  `ADDRESS1` varchar(200) default NULL,
  `ADDRESS2` varchar(200) default NULL,
  `CITY` varchar(50) default NULL,
  `STATE` varchar(20) default NULL,
  `ZIP` varchar(50) default NULL,
