  `DAILY_RATE` double default NULL,
  PRIMARY KEY  (`PARTY_ID`),
  KEY `ACCOUNT_ID` (`ACCOUNT_ID`)
) ENGINE=InnoDB DEFAULT CHARSET=latin1;

